{
  "name": "El Renacimiento del Alma 2026",
  "description": "Landing page para el libro digital de astrología y metafísica de Augusto Pinoff."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';
import Hero from './components/Hero';
import ContentPreview from './components/ContentPreview';
import TargetAudience from './components/TargetAudience';
import AboutAuthor from './components/AboutAuthor';
import PaperbackForm from './components/PaperbackForm';
import FinalCTA from './components/FinalCTA';

const App: React.FC = () => {
  return (
    <div className="min-h-screen font-sans text-slate-200 bg-slate-950 overflow-x-hidden selection:bg-amber-400 selection:text-slate-900">
      {/* Background Gradient Wrapper */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute inset-0 bg-gradient-to-br from-slate-950 via-violet-950 to-slate-900 opacity-100" />
        <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] bg-violet-600/20 rounded-full blur-[120px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600/10 rounded-full blur-[100px]" />
      </div>

      {/* Content */}
      <div className="relative z-10">
        <Hero />
        <ContentPreview />
        <TargetAudience />
        <AboutAuthor />
        <PaperbackForm />
        <FinalCTA />

        <footer className="py-8 text-center text-slate-500 text-sm border-t border-white/5">
          <p>© {new Date().getFullYear()} Augusto Pinoff. Todos los derechos reservados.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Heart, Compass, Lightbulb } from 'lucide-react';

const TargetAudience: React.FC = () => {
  const cards = [
    {
      icon: <Compass className="w-8 h-8 text-violet-300" />,
      text: "Para quienes aman la astrología y quieren algo más profundo, estructurado y útil que un horóscopo rápido de redes sociales."
    },
    {
      icon: <Heart className="w-8 h-8 text-rose-300" />,
      text: "Para quienes están en un proceso de cambio personal, sienten incertidumbre y buscan una guía clara para transitar el año."
    },
    {
      icon: <Lightbulb className="w-8 h-8 text-amber-300" />,
      text: "Para quienes se interesan por la metafísica, las leyes espirituales y quieren herramientas prácticas para el trabajo interior."
    }
  ];

  return (
    <section className="py-24 px-6 bg-slate-900/50">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="font-serif text-3xl md:text-4xl text-white mb-4">
            ¿Para quién es este libro?
          </h2>
          <p className="text-slate-400 max-w-2xl mx-auto">
            Este libro es para las personas que sienten que el 2026 no puede ser simplemente “un año más”, sino una oportunidad para vivir con mayor propósito.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-6">
          {cards.map((card, idx) => (
            <div key={idx} className="bg-slate-800/40 border border-slate-700/50 p-8 rounded-xl hover:border-amber-500/30 transition-colors duration-300 flex flex-col items-center text-center">
              <div className="mb-6 p-4 bg-slate-950 rounded-full border border-slate-800 shadow-lg">
                {card.icon}
              </div>
              <p className="text-slate-200 leading-relaxed font-light">
                {card.text}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default TargetAudience;

import React, { useState } from 'react';
import { Send, MapPin } from 'lucide-react';

const PaperbackForm: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const subject = encodeURIComponent(`Solicitud Libro Papel - ${formData.name}`);
    const body = encodeURIComponent(
      `Nombre: ${formData.name}\nEmail: ${formData.email}\n\nMensaje:\n${formData.message}`
    );
    window.location.href = `mailto:sofiapinoff@gmail.com?subject=${subject}&body=${body}`;
  };

  return (
    <section className="py-24 px-6 bg-gradient-to-b from-slate-900 to-slate-950">
      <div className="max-w-3xl mx-auto glass-card rounded-2xl p-8 md:p-12 shadow-2xl border border-amber-500/10">

        <div className="text-center mb-10">
          <div className="flex items-center justify-center gap-2 mb-4 text-amber-400">
            <MapPin size={20} />
            <span className="uppercase tracking-widest text-sm font-bold">Solo disponible en España</span>
          </div>
          <h2 className="font-serif text-3xl text-white mb-4">
            ¿Lo querés en formato papel?
          </h2>
          <p className="text-slate-400">
            Si vivís en España y preferís la experiencia de tener el libro en tus manos (tapa blanda con solapas), puedes solicitarlo directamente a través del siguiente formulario.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label htmlFor="name" className="block text-sm font-medium text-slate-300 mb-2">Nombre completo</label>
            <input
              type="text"
              id="name"
              name="name"
              required
              value={formData.name}
              onChange={handleChange}
              className="w-full bg-slate-800/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-amber-400 focus:ring-1 focus:ring-amber-400 transition-colors"
              placeholder="Tu nombre"
            />
          </div>

          <div>
            <label htmlFor="email" className="block text-sm font-medium text-slate-300 mb-2">Email de contacto</label>
            <input
              type="email"
              id="email"
              name="email"
              required
              value={formData.email}
              onChange={handleChange}
              className="w-full bg-slate-800/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-amber-400 focus:ring-1 focus:ring-amber-400 transition-colors"
              placeholder="tucorreo@ejemplo.com"
            />
          </div>

          <div>
            <label htmlFor="message" className="block text-sm font-medium text-slate-300 mb-2">Mensaje</label>
            <textarea
              id="message"
              name="message"
              rows={4}
              required
              value={formData.message}
              onChange={handleChange}
              className="w-full bg-slate-800/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-amber-400 focus:ring-1 focus:ring-amber-400 transition-colors"
              placeholder="Estoy en España y quiero solicitar mi libro en formato papel."
            ></textarea>
          </div>

          <button
            type="submit"
            className="w-full bg-slate-700 hover:bg-slate-600 text-white font-bold py-4 rounded-lg flex items-center justify-center gap-2 transition-all transform hover:-translate-y-1 shadow-lg"
          >
            <Send size={18} />
            Solicitar información por Email
          </button>
        </form>

        <p className="text-xs text-center text-slate-500 mt-4">
          Al hacer clic, se abrirá tu gestor de correo predeterminado para enviar la solicitud a sofiapinoff@gmail.com
        </p>
      </div>
    </section>
  );
};

export default PaperbackForm;

